#include <iostream>
#include <string>

class Percentage
{
    int m_value{0};
public:
    void set(int v)
    {
        if (v < 0)        m_value = 0;
        else if (v > 100) m_value = 100;
        else              m_value = v;
    }

    int get() const { return m_value; }
};

int main()
{
    int n{};
    std::cin >> n;

    Percentage p{};

    for (int i{0}; i < n; ++i)
    {
        std::string op{};
        std::cin >> op;

        if (op == "set")
        {
            int v{};
            std::cin >> v;
            p.set(v);
        }
        else
        {
            std::cout << "Value: " << p.get() << '\n';
        }
    }

    return 0;
}

